    {"type":"actions","elements":[{"type":"button","text":{"type":"plain_text","text":"✅ Approve"},"style":"primary","value":"approved","action_id":"invoice_approve"},{"type":"button","text":{"type":"plain_text","text":"❌ Reject"},"style":"danger","value":"rejected","action_id":"invoice_reject"},{"type":"button","text":{"type":"plain_text","text":"🚩 Flag"},"value":"flagged","action_id":"invoice_flag"}]}
